changeSet.sql:
-- Sequenze DUP INSERT INTO aurora.codice_sequence (codice_istat, entity_type, last_number) SELECT DISTINCT codice_istat, 'DUP', COALESCE(( SELECT COUNT(*) FROM aurora.dup d2 WHERE d2.codice_istat = d.codice_istat ), 0) FROM aurora.dup d ON CONFLICT DO NOTHING;
-- Sequenze Progetti (basate sul codice_istat del DUP) INSERT INTO aurora.codice_sequence (codice_istat, entity_type, last_number) SELECT DISTINCT dup.codice_istat, 'PRJ', COALESCE(( SELECT COUNT(*) FROM aurora.dup_progetti p2 INNER JOIN aurora.dup d2 ON p2.dup_id = d2.id WHERE d2.codice_istat = dup.codice_istat ), 0) FROM aurora.dup_progetti p INNER JOIN aurora.dup dup ON p.dup_id = dup.id ON CONFLICT DO NOTHING;
-- Sequenze Attività (basate sul codice_istat del DUP del progetto) INSERT INTO aurora.codice_sequence (codice_istat, entity_type, last_number) SELECT DISTINCT dup.codice_istat, 'ATT', COALESCE(( SELECT COUNT(*) FROM aurora.attivita a2 INNER JOIN aurora.dup_progetti p2 ON a2.progetto_id = p2.id INNER JOIN aurora.dup d2 ON p2.dup_id = d2.id WHERE d2.codice_istat = dup.codice_istat ), 0) FROM aurora.attivita a INNER JOIN aurora.dup_progetti p ON a.progetto_id = p.id INNER JOIN aurora.dup dup ON p.dup_id = dup.id ON CONFLICT DO NOTHING;
